// ── Validate & Classify Query Complexity ─────────────────────────────────
//
// Input  (from Webhook body): { query, cap?, model?, max_iterations? }
// Output: { query, cap, model, max_iterations, tier, classified_at }
//
// Tiers and their default token caps:
//   simple   → 15 000  (≤10 words, no comparison/multi-part signals)
//   complex  → 30 000  (moderate length or mixed intent)
//   deep     → 50 000  (multi-question, comparison, or explicit research ask)
//   custom   → caller-supplied cap (when `cap` is explicitly provided)

const body = $input.first().json.body || $input.first().json;

if (!body || typeof body.query !== 'string' || !body.query.trim()) {
  throw new Error('Request body must contain a non-empty `query` string.');
}

const query          = body.query.trim();
const requestedCap   = typeof body.cap === 'number' ? body.cap : null;
const model          = body.model          || 'claude-opus-4-6';
const maxIterations  = body.max_iterations || 8;

// Complexity signals
const wordCount          = query.split(/\s+/).length;
const questionMarks      = (query.match(/\?/g) || []).length;
const hasComparison      = /\b(compare|vs\.?|versus|difference|contrast|pros.*cons|advantages.*disadvantages)\b/i.test(query);
const hasResearchKeyword = /\b(research|analyze|analyse|explain|deep.?dive|comprehensive|overview|survey|summarize|summarise)\b/i.test(query);
const isMultiPart        = questionMarks > 1 || /;\s*(?:and|also|additionally)/i.test(query);

let tier, cap;
if (requestedCap !== null) {
  tier = 'custom';
  cap  = Math.max(1000, Math.min(200000, requestedCap));
} else if (wordCount <= 10 && !hasComparison && !isMultiPart && !hasResearchKeyword) {
  tier = 'simple';
  cap  = 15000;
} else if (isMultiPart || hasComparison || hasResearchKeyword) {
  tier = 'deep';
  cap  = 50000;
} else {
  tier = 'complex';
  cap  = 30000;
}

return [{
  json: {
    query,
    cap,
    model,
    max_iterations: maxIterations,
    tier,
    classified_at: new Date().toISOString()
  }
}];

// ── Format Success Response ──────────────────────────────────────────────
const agent  = $input.first().json;
const params = $('Validate & Classify').first().json;

const strategies = (agent.memory_strategies || []).join(', ') || 'none';
const subQCount  = (agent.sub_questions || []).length;

const metaLine = [
  `model=${params.model}`,
  `tier=${params.tier}`,
  `cap=${(params.cap || 0).toLocaleString()}`,
  `used=${(agent.tokens_total || 0).toLocaleString()} (${agent.budget_utilisation_pct || 0}%)`,
  `cost=$${(agent.cost_usd || 0).toFixed(6)}`,
  `memory=[${strategies}]`,
  `iter=${agent.iterations || 0}`,
  subQCount > 0 ? `sub_questions=${subQCount}` : null
].filter(Boolean).join('  |  ');

return [{
  json: {
    success: true,
    query:   params.query,
    answer:  agent.answer,
    meta:    metaLine,
    detail: {
      tier:               params.tier,
      model:              params.model,
      cap:                params.cap,
      tokens_input:       agent.tokens_input,
      tokens_output:      agent.tokens_output,
      tokens_total:       agent.tokens_total,
      budget_utilisation: agent.budget_utilisation_pct,
      cost_usd:           agent.cost_usd,
      memory_strategies:  agent.memory_strategies,
      sub_questions:      agent.sub_questions,
      iterations:         agent.iterations,
      classified_at:      params.classified_at
    }
  }
}];

// ── Format Error Response ────────────────────────────────────────────────
const err    = $input.first().json;
const params = $('Validate & Classify').first().json;

return [{
  json: {
    success: false,
    query:   params.query,
    error:   err.message || err.error || 'Agent API call failed',
    detail:  err
  }
}];
